SELECT TOP __[POSTCOMPILE_param_1] canonical.grouping_id, canonical.event_month, canonical.lag_day, canonical.load_epoch_day, canonical.batch_id, canonical.alt_value, canonical.row_count, canonical.n_curve_eligible, canonical.n_null_event_time, canonical.n_null_load_time_only, canonical.n_negative_clipped, canonical.n_negative_lag_excluded, canonical.n_overflow, canonical.n_join_unmatched, canonical.n_other_exclusions, canonical.n_base_rows, canonical.n_ambiguous_base_rows, canonical.n_compare_mismatch, canonical.max_lookup_dup, canonical.distinct_keys, canonical.min_load_time 
FROM (SELECT grouping([#mp_probe].event_month) * :grouping_1 + grouping([#mp_probe].lag_day) * :grouping_2 + grouping([#mp_probe].load_epoch_day) * :grouping_3 + :param_2 + :param_3 AS grouping_id, [#mp_probe].event_month AS event_month, [#mp_probe].lag_day AS lag_day, [#mp_probe].load_epoch_day AS load_epoch_day, max([#mp_probe].batch_id) AS batch_id, max([#mp_probe].alt_value) AS alt_value, count(*) AS row_count, coalesce(sum([#mp_probe].is_eligible), :coalesce_1) AS n_curve_eligible, coalesce(sum([#mp_probe].is_null_event_time), :coalesce_2) AS n_null_event_time, coalesce(sum([#mp_probe].is_null_load_time_only), :coalesce_3) AS n_null_load_time_only, coalesce(sum([#mp_probe].is_negative_clipped), :coalesce_4) AS n_negative_clipped, coalesce(sum([#mp_probe].is_negative_lag_excluded), :coalesce_5) AS n_negative_lag_excluded, coalesce(sum([#mp_probe].is_overflow), :coalesce_6) AS n_overflow, coalesce(sum([#mp_probe].is_join_unmatched), :coalesce_7) AS n_join_unmatched, CAST(:param_4 AS BIGINT) AS n_other_exclusions, coalesce(sum([#mp_probe].is_base_row), :coalesce_8) AS n_base_rows, coalesce(sum([#mp_probe].is_ambiguous_base), :coalesce_9) AS n_ambiguous_base_rows, coalesce(sum([#mp_probe].is_compare_mismatch), :coalesce_10) AS n_compare_mismatch, max([#mp_probe].lookup_dup) AS max_lookup_dup, CAST(NULL AS BIGINT) AS distinct_keys, min([#mp_probe].load_time) AS min_load_time 
FROM [#mp_probe] GROUP BY GROUPING SETS (([#mp_probe].event_month, [#mp_probe].lag_day), ([#mp_probe].load_epoch_day)) UNION ALL SELECT :param_5 AS grouping_id, CAST(NULL AS DATETIME) AS event_month, CAST(NULL AS INTEGER) AS lag_day, CAST(NULL AS DATETIME) AS load_epoch_day, CAST(NULL AS VARCHAR(max)) AS batch_id, CAST(NULL AS VARCHAR(max)) AS alt_value, count(*) AS row_count, coalesce(sum([#mp_probe].is_eligible), :coalesce_11) AS n_curve_eligible, coalesce(sum([#mp_probe].is_null_event_time), :coalesce_12) AS n_null_event_time, coalesce(sum([#mp_probe].is_null_load_time_only), :coalesce_13) AS n_null_load_time_only, coalesce(sum([#mp_probe].is_negative_clipped), :coalesce_14) AS n_negative_clipped, coalesce(sum([#mp_probe].is_negative_lag_excluded), :coalesce_15) AS n_negative_lag_excluded, coalesce(sum([#mp_probe].is_overflow), :coalesce_16) AS n_overflow, coalesce(sum([#mp_probe].is_join_unmatched), :coalesce_17) AS n_join_unmatched, CAST(:param_6 AS BIGINT) AS n_other_exclusions, coalesce(sum([#mp_probe].is_base_row), :coalesce_18) AS n_base_rows, coalesce(sum([#mp_probe].is_ambiguous_base), :coalesce_19) AS n_ambiguous_base_rows, coalesce(sum([#mp_probe].is_compare_mismatch), :coalesce_20) AS n_compare_mismatch, max([#mp_probe].lookup_dup) AS max_lookup_dup, CAST(NULL AS BIGINT) AS distinct_keys, min([#mp_probe].load_time) AS min_load_time 
FROM [#mp_probe]) AS canonical ORDER BY canonical.grouping_id
